import{_ as t,c as l,o as i,a1 as e}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"常見問題與優化：故障排除、CLI 命令、性能調優 | Clawdbot 教程","description":"解決 Clawdbot 使用中的常見問題、掌握完整的 CLI 命令參考、學習性能優化技巧，提升系統穩定性和響應速度。","frontmatter":{"title":"常見問題與優化：故障排除、CLI 命令、性能調優 | Clawdbot 教程","sidebarTitle":"遇到問題怎麼辦","subtitle":"常見問題與優化","description":"解決 Clawdbot 使用中的常見問題、掌握完整的 CLI 命令參考、學習性能優化技巧，提升系統穩定性和響應速度。","tags":["FAQ","故障排除","CLI","性能優化"],"order":300},"headers":[],"relativePath":"zh-tw/moltbot/moltbot/faq/index.md","filePath":"zh-tw/moltbot/moltbot/faq/index.md"}'),o={name:"zh-tw/moltbot/moltbot/faq/index.md"};function r(n,a,s,h,d,p){return i(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="常見問題與優化" tabindex="-1">常見問題與優化 <a class="header-anchor" href="#常見問題與優化" aria-label="Permalink to &quot;常見問題與優化&quot;">​</a></h1><p>本章節幫助你解決使用 Clawdbot 時遇到的各种問題，掌握完整的命令行操作方法，並學習如何優化系統性能。</p><div class="info custom-block"><p class="custom-block-title">學習順序建議</p><p>建議按以下順序閱讀本章節內容：</p><ol><li>先學習 <strong><a href="./cli-commands/">CLI 命令參考</a></strong> —— 掌握基礎操作和調試工具</li><li>再學習 <strong><a href="./troubleshooting/">故障排除</a></strong> —— 遇到問題時能快速定位和解決</li><li>最後學習 <strong><a href="./performance-optimization/">性能優化</a></strong> —— 提升系統運行效率</li></ol></div><h2 id="子頁面導航" tabindex="-1">子頁面導航 <a class="header-anchor" href="#子頁面導航" aria-label="Permalink to &quot;子頁面導航&quot;">​</a></h2><h3 id="故障排除" tabindex="-1"><a href="./troubleshooting/">故障排除</a> <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;[故障排除](./troubleshooting/)&quot;">​</a></h3><p>解決常見問題的全面排查指南，涵蓋：</p><ul><li>Gateway 啟動失敗</li><li>渠道連接問題（WhatsApp、Telegram、Slack 等）</li><li>認證錯誤和權限問題</li><li>工具調用失敗</li><li>會話管理異常</li></ul><p><strong>適用場景</strong>：當你遇到具體問題，需要快速排查和解決時。</p><hr><h3 id="cli-命令參考" tabindex="-1"><a href="./cli-commands/">CLI 命令參考</a> <a class="header-anchor" href="#cli-命令參考" aria-label="Permalink to &quot;[CLI 命令參考](./cli-commands/)&quot;">​</a></h3><p>完整的命令列表和用法說明，包括：</p><ul><li>Gateway 控制命令（啟動、重啟、狀態）</li><li>Agent 交互命令</li><li>模型管理和配置</li><li>渠道管理（登錄、狀態、登出）</li><li>會話管理（列表、重置、刪除、壓縮）</li><li>節點管理（列表、調用、配對）</li><li>技能管理和配置精靈</li></ul><p><strong>適用場景</strong>：需要快速查找某個命令的用法和參數，或學習 CLI 的完整功能。</p><hr><h3 id="性能優化" tabindex="-1"><a href="./performance-optimization/">性能優化</a> <a class="header-anchor" href="#性能優化" aria-label="Permalink to &quot;[性能優化](./performance-optimization/)&quot;">​</a></h3><p>提升 Gateway 性能和響應速度的優化技巧，涵蓋：</p><ul><li>提示詞緩存（Prompt Caching）降低成本</li><li>會話修剪（Session Pruning）減少上下文</li><li>並發控制和資源管理</li><li>記憶體優化和垃圾回收</li><li>日誌級別調優</li></ul><p><strong>適用場景</strong>：系統運行緩慢、資源佔用過高，或希望提升用戶體驗時。</p><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>在學習本章節之前，建議你已經完成：</p><ul><li>✅ <strong><a href="./../../start/getting-started/">快速開始</a></strong> —— 了解基本的安裝和配置流程</li><li>✅ <strong><a href="./../../start/gateway-startup/">啟動 Gateway</a></strong> —— 知道如何啟動和管理 Gateway</li></ul><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節後，你可以繼續學習：</p><ul><li><strong><a href="./../../appendix/config-reference/">完整配置參考</a></strong> —— 深入了解所有配置項的詳細說明</li><li><strong><a href="./../../appendix/deployment/">部署選項</a></strong> —— 學習如何在不同平台部署 Clawdbot</li><li><strong><a href="./../../appendix/development/">開發指南</a></strong> —— 了解插件開發和貢獻流程</li></ul>',24)])])}const u=t(o,[["render",r]]);export{m as __pageData,u as default};
